def classify_intent(query: str) -> str:
    prompt = f"Classify intent: {query}\nOptions: RAG|TOOL|DIRECT"
    response = stack.generate(prompt, max_tokens=10)
    return response.content.strip().upper()

intent = classify_intent('What’s the weather in NYC?')
# Returns: 'TOOL'

def rag_query(query: str):
    docs = stack.memory.retrieval_query(
        query=query,
        top_k=5,
        namespace='chatbot_docs'
    )
    context = '\n'.join([doc.page_content for doc in docs])
    return stack.generate(f"Answer using context: {context}\nQuery: {query}")

response = rag_query('Explain JWT tokens')

def agent_turn(user_input: str, conversation_history: list):
    stack.memory.add_turn(user_input, role='user')

    for _ in range(5):  # Max 5 turns
        intent = classify_intent(user_input)

        if intent == 'RAG':
            response = rag_query(user_input)
        elif intent == 'TOOL':
            response = stack.tools.execute(user_input)
        else:
            response = stack.generate(user_input)

        stack.memory.add_turn(response.content, role='assistant')
        if response.converged:
            break

    return response.content

