from vex import verify, Guardrail

@verify(
    guards=[
        Guardrail.SAFETY_HIGH,
        Guardrail.RESPONSE_ACCURACY,
        Guardrail.CONVERSATION_COHERENCE,
        Guardrail.PII_REDACTION,
        Guardrail.HALLUCINATION_LOW
    ],
    risk_profile='high'
)
def safe_agent_turn(user_input: str, history: list) -> str:
    raw_response = agent_turn(user_input, history)
    return raw_response

# Usage
try:
    verified_response = safe_agent_turn('Find flight to Tokyo', history)
